(lib.LevelSelect = function(mode,startPosition,loop) {
	this.initialize(mode,startPosition,loop,{});

	// timeline functions:
	this.frame_0 = function() {
		var levelSelect = this;
		gamevars(6, [onMouseClick]);
		createjs.Tween.get(levelSelect).wait(5).call(initLevelBtns);
		var lbsts = [];
		var startLevel = 1;
		function initLevelBtns() {
			var sx = 401.5;
			var sy = 231.75;
			var inc = 119.25;
			for (var i = startLevel; i < startLevel + 15; i++) {
				var lbtn = new lib.LevelS();
				lbtn.name = "lbtn";
				lbtn.txt.text = i + "";
				lbtn.txt1.text = i + "";
				lbtn.x = sx;
				lbtn.y = sy;
				sx += inc;
				lbtn.gotoAndStop(0);
				lbtn.bkc.gotoAndStop(i % 6);
				if (i > (gamevars(0).sobj.currentLevel)) {
					lbtn.gotoAndStop(1);
					lbtn.mouseEnabled = false;
				}
				lbtn.mouseChildren = false;
				lbtn.cursor = "pointer";
				levelSelect.addChild(lbtn);
				if (i % 5 == 0) {
					sx = 401.5;
					sy += inc
				}
				lbsts.push(lbtn);
			}
			startLevel = (Math.floor(gamevars(0).sobj.currentLevel / 15) * 15) + 1;
			if (startLevel > gamevars(0).totalLevels) {
				startLevel -= 15;
			}
			updateLevels();
		}
		function updateLevels() {
			var idx = 0;
			for (var i = startLevel; i < startLevel + 15; i++) {
				var lbtn = lbsts[idx];
				lbtn.txt.text = i + "";
				lbtn.txt1.text = i + "";
				lbtn.gotoAndStop(0);
				lbtn.mouseEnabled = true;
				if (i > (gamevars(0).sobj.currentLevel)) {
					lbtn.gotoAndStop(1);
					lbtn.mouseEnabled = false;
				}
				lbtn.mouseChildren = false;
				idx++;
			}
		}
		function createGamePlay() {
			gamevars(7, [onMouseClick]);
			gamevars(4, levelSelect);
			gamevars(3, new lib.IntroScreen());
		}
		function onMouseClick(event) {
			if (event.target.name == "lbtn") {
				var lno = Number(event.target.txt.text);
				gamevars(0).playingLevel = lno;
				gamevars(7, [onMouseClick]);
				gamevars(4, levelSelect);
				gamevars(3, new lib.GamePlay());
			}
			switch (event.target.getName()) {
				case "mainMenu":
					gv.nextCallFunction = createGamePlay;
					if (typeof sdk !== 'undefined' && sdk.showBanner !== 'undefined') {
						sdk.showBanner();
					} else {
						createGamePlay();
					}
		
		
					break;
				case "nextLevels":
					if (startLevel + 14 == gamevars(0).totalLevels) {
						return;
					} else {
						startLevel += 15;
						updateLevels();
					}
					break;
				case "prevLevels":
					if (startLevel == 1) {
						return;
					} else {
						startLevel -= 15;
						updateLevels();
					}
					break;
			}
		}
	}

	// actions tween:
	this.timeline.addTween(cjs.Tween.get(this).call(this.frame_0).wait(1));

	// Layer 2
	this.instance = new lib.Bitmap59();
	this.instance.parent = this;
	this.instance.setTransform(315,160);

	this.nextLevels = new lib.nextLevelButton();
	this.nextLevels.name = "nextLevels";
	this.nextLevels.parent = this;
	this.nextLevels.setTransform(1034.8,342.9,1.324,1.324);
	new cjs.ButtonHelper(this.nextLevels, 0, 1, 2, false, new lib.nextLevelButton(), 3);

	this.prevLevels = new lib.nextLevelButton();
	this.prevLevels.name = "prevLevels";
	this.prevLevels.parent = this;
	this.prevLevels.setTransform(245.2,342.9,1.324,1.324,0,0,180);
	new cjs.ButtonHelper(this.prevLevels, 0, 1, 2, false, new lib.nextLevelButton(), 3);

	this.instance_1 = new lib.Bitmap12();
	this.instance_1.parent = this;
	this.instance_1.setTransform(241,20);

	this.mainMenu = new lib.MainMenu();
	this.mainMenu.name = "mainMenu";
	this.mainMenu.parent = this;
	this.mainMenu.setTransform(639.7,621.1,1.324,1.324);
	new cjs.ButtonHelper(this.mainMenu, 0, 1, 2, false, new lib.MainMenu(), 3);

	this.instance_2 = new lib.Background();
	this.instance_2.parent = this;

	this.timeline.addTween(cjs.Tween.get({}).to({state:[{t:this.instance_2},{t:this.mainMenu},{t:this.instance_1},{t:this.prevLevels},{t:this.nextLevels},{t:this.instance}]}).wait(1));

}).prototype = getMCSymbolPrototype(lib.LevelSelect, new cjs.Rectangle(0,0,1280,720), null);


