		function onMouseTouchUps(e) {
			if (gameplay.cPowerMC) {
				gameplay.removeChild(gameplay.cPowerMC);
				var p = gameplay.globalToLocal(e.stageX, e.stageY);
				var blockMC = gameplay.getObjectUnderPoint(p.x, p.y, 1);
				if (blockMC  && blockMC.name == "Block") {
					switch (gameplay.cPowerMC.name) {
						case "HAMMER":
							playSFX("HammerSound");
							pObj["HAMMER"] -= 1;
							powerTurn = true;
							removeAItem(blockMC);
							gameplay.mouseEnabled = false;
							gameplay.mouseChildren = false;
							shiftAllItems();
							break;
						case "BOMB":
							pObj["BOMB"] -= 1;
							playSFX("BombSound");
							powerTurn = true;
							var bombArray = [blockMC,
								blockMC.top,
								blockMC.down,
								blockMC.left,
								blockMC.left ? blockMC.left.top : null,
								blockMC.left ? blockMC.left.down : null,
								blockMC.right,
								blockMC.right ? blockMC.right.top : null,
								blockMC.right ? blockMC.right.down : null,
								blockMC.top ? blockMC.top.left : null,
								blockMC.top ? blockMC.top.right : null,
								blockMC.down ? blockMC.down.left : null,
								blockMC.down ? blockMC.down.right : null
							];
							while (bombArray.length > 0) {
								rBlock = bombArray[0];
								while (bombArray.indexOf(rBlock) >= 0) {
									bombArray.splice(bombArray.indexOf(rBlock), 1);
								}
								if (rBlock != null) {
									createjs.Tween.get(rBlock, {
										useTicks: true
									}).wait(5).call(removeAItem, [rBlock]);
		
								}
							}
							var blast = new lib.Blast();
							blast.x = blockMC.x;
							blast.y = blockMC.y;
							gameplay.addChild(blast);
							gameplay.mouseEnabled = false;
							gameplay.mouseChildren = false;
							createjs.Tween.get(gameplay, {
								useTicks: true
							}).wait(10).call(shiftAllItems);
							break;
						case "ARROW":
							pObj["ARROW"] -= 1;
							playSFX("BladeSound");
							powerTurn = true;
							for (rBlock of blockArray) {
								if (rBlock.x == blockMC.x || rBlock.y == blockMC.y) {
									//removeAItem(rBlock);
									createjs.Tween.get(rBlock, {
										useTicks: true
									}).wait(7).call(removeAItem, [rBlock]);
								}
							}
							gameplay.mouseEnabled = false;
							gameplay.mouseChildren = false;
							var obj = {
								left: blockMC.x,
								right: blockMC.y,
								up: blockMC.y,
								down: blockMC.y,
								x: blockMC.x,
								y: blockMC.y
							};
							createjs.Tween.get(obj, {
								useTicks: true
							}).to({
								left: 0,
								right: 1280,
								up: 0,
								down: 720
							}, 12).addEventListener("change", createArrowParticles, false);
							createjs.Tween.get(gameplay, {
								useTicks: true
							}).wait(20).call(shiftAllItems);
							//shiftAllItems();
							break;
						case "MAGNET":
							playSFX("MagnetSound");
							pObj["MAGNET"] -= 1;
							powerTurn = true;
							for (rBlock of blockArray) {
								if (rBlock.cFrame == blockMC.cFrame) {
									createjs.Tween.get(rBlock, {
										useTicks: true
									}).wait(7).call(removeAItem2, [rBlock, blockMC]);
								}
							}
							gameplay.mouseEnabled = false;
							gameplay.mouseChildren = false;
							obj = {
								val: 0.5,
								x: blockMC.x,
								y: blockMC.y
		
							};
							createjs.Tween.get(obj, {
								useTicks: true
							}).to({
								val: 2.5
							}, 12).addEventListener("change", createMagnets, false);
							createjs.Tween.get(gameplay, {
								useTicks: true
							}).wait(13).call(shiftAllItems);
							break;
					}
		
				} 
				gameplay.cPowerMC = null;
			}
			gameplay.pinfo.visible = false;
			
			doTouchListen(false);
		}
		function createMagnets(e) {
			var obj = e.target.target;
			var p = new lib.MagnerPart();
			p.regX = 417;
			p.regY = 417;
			p.x = obj.x;
			p.y = obj.y;
			p.scaleX = 0.1;
			p.scaleY = 0.1;
			gameplay.addChild(p);
		
			createjs.Tween.get(p, {
				useTicks: true
			}).to({
				scaleX: obj.val,
				scaleY: obj.val,
				alpha: 0.5
			}, 5).call(removeItem, [p]);
		}
		function createArrowPart(x, y) {
			var arrprt = new lib.ArrowPart();
			arrprt.regX = 56;
			arrprt.regY = 56;
			arrprt.x = x;
			arrprt.y = y;
			arrprt.scaleX = 0;
			arrprt.scaleY = 0;
			gameplay.addChild(arrprt);
			createjs.Tween.get(arrprt, {
				useTicks: true
			}).to({
				scaleX: 2,
				scaleY: 2,
				alpha: 0.5
			}, 12).call(removeItem, [arrprt]);
		
		}
		function createArrowParticles(e) {
			var obj = e.target.target;
			createArrowPart(obj.left, obj.y);
			createArrowPart(obj.right, obj.y);
			createArrowPart(obj.x, obj.up);
			createArrowPart(obj.x, obj.down);
		}
		function onPressMoves(e) {
			if (gameplay.cPowerMC) {
				var p = gameplay.globalToLocal(e.stageX, e.stageY);
				gameplay.cPowerMC.x = p.x;
				gameplay.cPowerMC.y = p.y;
			}
		}
		
		
		
		
		function updatePowerInfo(title, desc) {
			gameplay.addChild(gameplay.pinfo);
			gameplay.pinfo.visible = true;
			gameplay.pinfo.pnameTxt.text = title;
			gameplay.pinfo.descTxt.text = desc;
			gameplay.pinfo.stText.text = pObj[title] > 0 ? +pObj[title] + " UNITS" : "NOT AVAILABLE";
		
		}
		function showPowerInfo(targetName) {
			switch (targetName) {
				case "magnetPower":
					updatePowerInfo("MAGNET", "Drag and Drop on tile to remove all similar tiles, this will not count as a turn");
					break;
				case "hammerPower":
					updatePowerInfo("HAMMER", "Drag and drop on a tile to remove it, this will not count as a turn.");
					break;
				case "bombPower":
					updatePowerInfo("BOMB", "Drag and Drop on a tile to remove it and its neighbors, this will not count as a turn.");
					break;
				case "arrowPower":
					updatePowerInfo("BLADES", "Drag and Drop on tile to remove the row and column of the tile, this will not count as a turn.");
					break;
				case "hintPower":
					updatePowerInfo("HINT", "Click to find a tile to swap. These are limited for a level.");
					break;
				case "ultraPower":
					updatePowerInfo("DOUBLE", "Cast this before making a match or using other speel, to double the collections.");
					break;
				default:
					gameplay.pinfo.visible = false;
					break;
			}
		}
		function addPowerMC(instance, name) {
			gameplay.cPowerMC = instance;
			gameplay.cPowerMC.name = name;
			gameplay.cPowerMC.mouseEnabled = false;
			gameplay.cPowerMC.regX = 56;
			gameplay.cPowerMC.regY = 128;
			gameplay.addChild(gameplay.cPowerMC);
			
		}
		function onMouseDown(e) {
			switch (e.target.getName()) {
				case "magnetPower":
					if (pObj["MAGNET"] != 0) {
						addPowerMC(new lib.MagnetBitmap(), "MAGNET");
						onPressMoves(e);
					}
					break;
				case "hammerPower":
					if (pObj["HAMMER"] != 0) {
						addPowerMC(new lib.HammerBitmap(), "HAMMER");
						onPressMoves(e);
					}
					break;
				case "bombPower":
					if (pObj["BOMB"] != 0) {
						addPowerMC(new lib.BombBitmap(), "BOMB");
						onPressMoves(e);
					}
					break;
				case "arrowPower":
					if (pObj["ARROW"] != 0) {
						addPowerMC(new lib.ArrowBitmap(), "ARROW");
						onPressMoves(e);
					}
					break;
			}
			showPowerInfo(e.target.getName());
			if (gameplay.cPowerMC) {
				gameplay.addChild(gameplay.cPowerMC);
			}
			var target = e.target;
			if (target.name == "Block") {
				if (firstItem == null) {
					firstItem = target;
					doTouchListen(true);
					showSelClip(true);
				} else if (secondItem == null && target != firstItem && [firstItem.left, firstItem.right, firstItem.top, firstItem.down].indexOf(target) >= 0) {
					secondItem = target;
					swapBoth(setPositions);
					doTouchListen(false);
				} else {
					firstItem = target;
					showSelClip(true);
					doTouchListen(true);
				}
			}
		}
		
		function showSelClip(bool) {
			if (bool) {
				gameplay.selClip.mouseChildren = false;
				gameplay.selClip.mouseEnabled = false;
				gameplay.selClip.play();
				gameplay.selClip.visible = true;
				gameplay.selClip.x = firstItem.x;
				gameplay.selClip.y = firstItem.y;
				gameplay.addChild(gameplay.selClip);
			} else {
				gameplay.selClip.stop();
				gameplay.selClip.visible = false;
			}
		}
		
		function doTouchListen(bool) {
			if (bool) {
				gamevars(32,[onTouchMoves]);		
			} else {
				gamevars(33,[onTouchMoves]);	
					
			}
		}
		function onTouchMoves(e) {
			var fx = firstItem.x;
			var fy = firstItem.y;
			var p = gameplay.globalToLocal(e.stageX, e.stageY);
			var mx = p.x;
			var my = p.y;
			var dx = mx - fx;
			var dy = my - fy;
			var dist = Math.sqrt(dx * dx + dy * dy);
			if (dist > blkDiff / 1.5) {
				if (Math.abs(dx) > Math.abs(dy)) {
					secondItem = dx > 0 ? firstItem.right : firstItem.left;
				} else {
					secondItem = dy > 0 ? firstItem.down : firstItem.top;
				}
				if (secondItem != null && secondItem.name == "Block") {
					doTouchListen(false);
					swapBoth(setPositions);
					return;
				}
			}
			secondItem = null;
		}
		function onMouseClick(e) {
			switch (e.target.getName()) {
				case "hintPower":
					if (pObj["HINT"] != 0) {
						playSFX("HintSound");
						if (dummyMatchCheck(true)) {
							pObj["HINT"] -= 1;
						} else {
							var bit = new lib.NoValidSwap;
							bit.x = 550;
							bit.y = 360;
							gameplay.parent.addChild(bit);
							bit.mouseEnabled = false;
							createjs.Tween.get(bit, {
								useTicks: true
							}).wait(40).call(removeItem, [bit]);
							pObj["HAMMER"] += 1;
						}
					}
					break;
				case "ultraPower":
					if (pObj["DOUBLE"] != 0 && gameplay.upp == null) {
						pObj["DOUBLE"] -= 1;
						activePower = "DOUBLE";
						var upower = new lib.UltraPower();
						gameplay.addChild(upower);
						upower.x = 1144;
						upower.y = 570;
						gameplay.upp = upower;
					}
					break;
				case "exitGame":
					pauseGame();
					var abcd = new lib.ConfirmPopUp();
					gamevars(3, abcd);
					abcd.yesSurrender = onYesSurr;
					abcd.noSurrender = resumeGame;
					return;
					break;
				case "pauseBtn":
					pauseGame();
					var pscreen = new lib.PauseScreen();
					pscreen.resumeGame = resumeGame;
					gamevars(3, pscreen);
					return;
					break;
					/*case "exitGame":
					removeThis();
					gamevars(0).playingLevel++;
					gamevars(4, gameplay);
					createjs.Tween.removeAllTweens();
					gamevars(3, new lib.GamePlay());
					break;*/
		
			}
		}
		function resumeGame() {
			createjs.Ticker.paused = false;
			gamePaused = false;
		}
		function onNoSurr() {
			resumeGame();
		}
		function pauseGame() {
			createjs.Ticker.paused = true;;
			gamePaused = true;
		}
		function onYesSurr() {
			resumeGame();
			removeThis();
			gamevars(4, gameplay);
			createjs.Tween.removeAllTweens();
			gamevars(3, new lib.IntroScreen());
		}
		
		//====================================================================================================================================================================
		
		//########  G A M E  -  E N G I N E  ####################################################################################################################
		function cleanBoard() {
			while (true) {
				var arr = getAllMatches();
				if (arr.length == 0) {
					return;
				}
				for (var blks of arr) {
					var arrFRG = [1, 2, 3, 4, 5];
					arrFRG.splice(arrFRG.indexOf(blks.cFrame), 1);
					var frm_id = arrFRG[Math.floor(Math.random() * arrFRG.length)];
					blks.updateFrame(frm_id);
		
				}
			}
		}
		function swapItems(b1, b2) {
		
			var tmp = b1.item;
			b1.updateMatchItem(b2.item);
			b2.updateMatchItem(tmp);
		}
		function dummyMatchCheck(bool = false) {
			var idxArr = [];
			for (var i = 0; i < blockArray.length; i++) {
				idxArr.push(i);
			}
			randomizeArray(idxArr);
			for (i = 0; i < idxArr.length; i++) {
				var cBlock = blockArray[idxArr[i]];
				if (cBlock.right) {
					swapItems(cBlock, cBlock.right);
					var matches = getAllMatches();
					swapItems(cBlock, cBlock.right);
					if (matches.length >= 3) {
						if (bool) {
							rotateTween(cBlock.item);
							rotateTween(cBlock.right.item);
						}
						return true;
					}
				}
				if (cBlock.down) {
					swapItems(cBlock, cBlock.down);
					var matches = getAllMatches();
					swapItems(cBlock, cBlock.down);
					if (matches.length >= 3) {
						if (bool) {
							rotateTween(cBlock.item);
							rotateTween(cBlock.down.item);
						}
						return true;
					}
				}
			}
			return false;
		}
		function rotateTween(item) {
			createjs.Tween.removeTweens(item);
			item.rotation = 0;
			createjs.Tween.get(item, {
				useTicks: true
			}).to({
				rotation: 360
			}, 24).wait(2);
		}
		function getAllMatches() {
			var matches = [];
			var sItem;
			var tmparr;
			var blk;
			for (blk of blockArray) {
				sItem = blk;
				tmparr = [sItem];
				while (sItem.right != null && sItem.cFrame == sItem.right.cFrame) {
					tmparr.push(sItem.right);
					sItem = sItem.right;
				}
				if (tmparr.length >= 3) {
					for (var mat of tmparr) {
						if (matches.indexOf(mat) < 0) {
							matches.push(mat);
						}
					}
				}
				sItem = blk;
				tmparr = [sItem];
				while (sItem.down != null && sItem.cFrame == sItem.down.cFrame) {
					tmparr.push(sItem.down);
					sItem = sItem.down;
				}
				if (tmparr.length >= 3) {
					for (mat of tmparr) {
						if (matches.indexOf(mat) < 0) {
							matches.push(mat);
						}
					}
				}
			}
			return matches;
		}
		
		function swapBoth(functionName) {
			createjs.Tween.removeTweens(firstItem.item);
			createjs.Tween.removeTweens(secondItem.item);
			firstItem.item.rotation = 0;
			secondItem.item.rotation = 0;
			showSelClip(false);
			gameplay.mouseEnabled = false;
			gameplay.mouseChildren = false;
			var p1 = {
				x: firstItem.item.x,
				y: firstItem.item.y
			};
			var p2 = {
				x: secondItem.item.x,
				y: secondItem.item.y
			};
			gameplay.addChild(firstItem.item);
			gameplay.addChild(secondItem.item);
			createjs.Tween.get(firstItem.item, {
				useTicks: true
			}).to({
				x: p2.x,
				y: p2.y
			}, 5);
			createjs.Tween.get(secondItem.item, {
				useTicks: true
			}).to({
				x: p1.x,
				y: p1.y
			}, 6).call(functionName);
		
		}
		function removeItem(itm) {
			if (itm.parent) {
				itm.parent.removeChild(itm);
			}
		}
		function removeAItem2(rBlock, b2) {
			if (activePower == "DOUBLE") {
				gifts += 2;
			} else {
				gifts++;
			}
			updateHud();
			createjs.Tween.removeTweens(rBlock.item);
			rBlock.item.rotation = 1;
			createjs.Tween.get(rBlock.item, {
				useTicks: true
			}).to({
				alpha: 0.5,
				rotation: 360,
				scaleX: 2,
				scaleY: 2,
				x: b2.x,
				y: b2.y
			}, 8).call(removeItem, [rBlock.item]);
			createjs.Tween.get(this, {
				useTicks: true
			}).wait(4).call(initParticalMC, [b2, 20]);
			rBlock.item = null;
		}
		function initParticalMC(rBlock, nBlock = 4) {
			var particleEffect = new lib.ParticalEffect();
			particleEffect["frameNum"] = rBlock.cFrame;
			particleEffect["numParts"] = nBlock;
			gameplay.addChild(particleEffect);
			particleEffect.x = rBlock.x;
			particleEffect.y = rBlock.y;
			
		}
		function removeAItem(rBlock) {
			if (activePower == "DOUBLE") {
				gifts += 2;
			} else {
				gifts++;
			}
			updateHud();
			createjs.Tween.removeTweens(rBlock.item);
			rBlock.item.rotation = 1;
			createjs.Tween.get(rBlock.item, {
				useTicks: true
			}).to({
				alpha: 0.4,
				rotation: 360,
				scaleX: 2,
				scaleY: 2
			}, 5).call(removeItem, [rBlock.item]);
			initParticalMC(rBlock, 10);
			rBlock.item = null;
		
		}
		function keepMatching() {
			var matchedArr = getAllMatches();
			if (matchedArr.length >= 3) {
				playSFX("MatchSound");
				if (powerTurn == false) {
					matchedInTurn += matchedArr.length;
				}
				for (var rBlock of matchedArr) {
		
					removeAItem(rBlock);
				}
				shiftAllItems();
			} else {
				var addedPName = "NONE";
				var ran = Math.ceil(Math.random() * 10);
				if (matchedInTurn > 12) {
					if (ran <= 4) {
						pObj["MAGNET"] += 1;
						addedPName = "Magnet";
					} else if (ran <= 8) {
						pObj["BLADES"] += 1;
						addedPName = "Arrow";
					} else {
						pObj["DOUBLE"] += 1;
						addedPName = "Ultra";
					}
				} else if (matchedInTurn > 9) {
					if (ran <= 4) {
						pObj["BOMB"] += 1;
						addedPName = "Bomb";
					} else if (ran <= 4) {
						pObj["DOUBLE"] += 1;
						addedPName = "Ultra";
					} else {
						if (Math.random() < 0.5) {
							pObj["MAGNET"] += 1;
							addedPName = "Magnet";
						} else {
							pObj["BLADES"] += 1;
							addedPName = "Arrow";
						}
					}
				} else if (matchedInTurn > 6) {
					if (ran <= 7) {
						pObj["DOUBLE"] += 1;
						addedPName = "Ultra";
					} else {
						if (Math.random() < 0.5) {
							pObj["BLADES"] += 1;
							addedPName = "Arrow";
						} else {
							pObj["BOMB"] += 1;
							addedPName = "Bomb";
						}
					}
				}
				if (addedPName != "NONE") {
					var bit = new lib[addedPName + "PP"];
					bit.x = 500;
					bit.y = 200;
					gameplay.parent.addChild(bit);
					bit.mouseEnabled = false;
					createjs.Tween.get(bit, {
						useTicks: true
					}).to({
						y: -50
					}, 50).call(removeItem, [bit]);
		
				}
				powerTurn = false;
				gameplay.mouseEnabled = true;
				gameplay.mouseChildren = true;
		
				firstItem = null;
				secondItem = null;
				matchedInTurn = 0;
				activePower = "NONE";
				if (gameplay.upp) {
					gameplay.removeChild(gameplay.upp);
					gameplay.upp = null;
				}
				if (dummyMatchCheck(false) == false) {
					var bit = new lib.NoValidSwap;
					bit.x = 500;
					bit.y = 360;
					gameplay.parent.addChild(bit);
					bit.mouseEnabled = false;
					createjs.Tween.get(bit, {
						useTicks: true
					}).wait(40).call(removeItem, [bit]);
					pObj["HAMMER"] += 1;
				}
		
				if (gifts >= targetNum) {
					removeThis();
					var score = 1000 + (turns / 2 + 0.5) * turns * 50;
					gamevars(0).sobj.scores[gamevars(0).playingLevel] = (score);
					gamevars(4, gameplay);
					gamevars(0).saveGame();
					if (gamevars(0).playingLevel == gamevars(0).sobj.currentLevel) {
						gamevars(0).sobj.currentLevel++;
					}
					gamevars(0).saveGame()
					if (gamevars(0).playingLevel == gamevars(0).totalLevels) {
						gamevars(3, new lib.WinScreen());
					} else {
						gamevars(3, new lib.LevelUp());
					}
				}
				if (turns == 0) {
					removeThis();
					gamevars(4, gameplay);
					gamevars(3, new lib.GameOver());
				}
			}
		}
		function setPositions() {
			var tmp = firstItem.item;
			firstItem.updateMatchItem(secondItem.item);
			secondItem.updateMatchItem(tmp);
			var matchedArr = getAllMatches();
			if (matchedArr.length >= 3) {
				turns--;
				updateHud();
				keepMatching();
			} else {
				swapBoth(restartMouse);
			}
		}
		function getUpTile(rBlock) {
			var upTile = null;
			if (upTile == null) {
				upTile = rBlock.top;
			}
			if (upTile == null) {
				upTile = rBlock.left != null ? rBlock.left.top : null;
			}
			if (upTile == null) {
				upTile = rBlock.right != null ? rBlock.right.top : null;
			}
			return upTile;
		}
		function setProps(rBlockp) {
			rBlockp.updateMatchItem(rBlockp.item);
		}
		function shiftAllItems() {
			var nf = false;
			for (var rBlock of blockArray) {
				if (rBlock.item == null) {
					nf = true;
					var upTile = getUpTile(rBlock);
					if (upTile == null) {
						rBlock.updateFrame(Math.floor(Math.random() * total_match_items));
						rBlock.item.y -= blkDiff;
					} else {
						rBlock.item = upTile.item;
						gameplay.addChild(rBlock.item);
						upTile.item = null;
					}
				}
			}
			if (nf == true) {
				shiftAllItems();
				return;
			}
			for (rBlock of blockArray) {
				if (rBlock.item != null) {
					if (rBlock.item.x != rBlock.x || rBlock.item.y != rBlock.y) {
						createjs.Tween.get(rBlock.item, {
							useTicks: true
						}).to({
							y: rBlock.y,
							x: rBlock.x
						}, 12, createjs.Ease.none).call(setProps, [rBlock]);
					}
				}
			}
			createjs.Tween.get(this, {
				useTicks: true
			}).wait(13).call(keepMatching);
		
		}
		function restartMouse() {
			var tmp = firstItem.item;
			firstItem.updateMatchItem(secondItem.item);
			secondItem.updateMatchItem(tmp);
			gameplay.mouseEnabled = true;
			gameplay.mouseChildren = true;
			firstItem = null;
			secondItem = null;
		}
